INSERT INTO `announcement` VALUES (2,'欢迎来到龙族社区','各位学员，欢迎加入混血种社区。本社区包含学院新闻、守夜人讨论区、诺玛邮件系统及联系人等板块。请遵守学院规章，文明交流。愿秘党之光与你同在。',1,1,'2026-07-10 12:12:07','2026-07-10 14:30:37');
/*!40000 ALTER TABLE `announcement` ENABLE KEYS */;
