INSERT INTO `comment` VALUES (474,11,42,'炼金物品失踪不是小事。建议先检查冰窖的出入记录。',NULL,'2026-07-08 10:04:49'),(475,11,43,'加图索家有一些炼金术方面的资料，需要的话可以借阅。',NULL,'2026-07-09 12:03:49'),(476,11,45,'我好像在诺玛的交易板上看到过有人在卖这类东西。',NULL,'2026-07-08 16:25:49'),(477,11,47,'执行部已关注此事。近期会加强冰窖周边巡逻。',NULL,'2026-07-11 04:11:49'),(478,12,42,'图书馆地下的东西，看到了就当没看到。',NULL,'2026-07-11 03:59:49'),(479,12,45,'师弟，图书馆地下三层以后别去了。师兄我当年也去过，然后被施耐德教授训了三个小时。',NULL,'2026-07-10 06:58:49'),(480,12,50,'图书馆地下的区域属于禁区，擅自进入将按校规处理。',NULL,'2026-07-11 07:08:49'),(481,12,46,'哇你看到了什么？是不是那个发光的封印阵？我也见过！',NULL,'2026-07-08 17:36:49'),(482,12,47,'……又是图书馆。我已经不想再写关于图书馆的报告了。',NULL,'2026-07-08 12:34:49'),(483,13,43,'楚会长每年招新都这么认真。学生会这边也欢迎新人。',NULL,'2026-07-11 03:34:49'),(484,13,46,'狮心会招新啦！师妹们快来报名，师姐带你们飞！',NULL,'2026-07-11 06:43:49'),(485,13,45,'加入狮心会可以免体能测试吗？不能？那我不加了。',NULL,'2026-07-10 15:54:49'),(486,13,42,'报名截止本周五。过期不候。',NULL,'2026-07-10 12:22:49'),(487,15,43,'作为学生会主席，照顾新生是应该的。',NULL,'2026-07-08 18:59:49'),(488,15,44,'哈哈哈哈哈我就知道这事会上论坛。恺撒你是真的很宠他。',NULL,'2026-07-10 15:13:49'),(489,15,45,'主席你什么时候也帮我订个座？我已经三年没被人请过客了。',NULL,'2026-07-08 13:38:49'),(490,15,51,'路明非哥哥有很多人照顾呢。绘梨衣也想要被照顾！',NULL,'2026-07-08 11:55:49'),(491,15,52,'哥哥人缘真好呢。不过……那些人真的只是\"照顾\"吗？',NULL,'2026-07-10 05:52:49'),(492,16,43,'今年自由一日的确准备不足。明年不会了。',NULL,'2026-07-10 17:17:49'),(493,16,42,'狮心会的战术配合更默契而已。明年你们可以改进。',NULL,'2026-07-10 13:04:49'),(494,16,45,'主席你不能全怪路明非啊，他一个人扛了对面三个！虽然是误打误撞。',NULL,'2026-07-09 17:30:49'),(495,16,44,'我在旁边看了全程，说实话路明非那个躲闪动作真的可以。',NULL,'2026-07-10 22:32:49'),(496,16,47,'战报已收录至执行部档案。数据翔实，分析到位。',NULL,'2026-07-09 07:51:49'),(497,17,42,'这些史料我在狮心会的旧档案里见过。可信度很高。',NULL,'2026-07-09 08:21:49'),(498,17,49,'这些资料涉及保密等级。建议不要在公开论坛讨论。',NULL,'2026-07-09 11:08:49'),(499,17,16,'历史总是由胜利者书写的。但真相……往往藏在字里行间。',NULL,'2026-07-08 15:04:49'),(500,17,50,'如需查阅相关档案，请通过诺玛提交正式申请。',NULL,'2026-07-08 21:18:49'),(501,20,42,'3E考试的核心是心像考验。不要试图控制它，让它自然发生。',NULL,'2026-07-09 12:56:49'),(502,20,43,'镰鼬就是在3E考试中觉醒的。那种感觉很难描述——就像世界突然有了声音。',NULL,'2026-07-09 02:21:49'),(503,20,45,'我考了三次3E才勉强通过。师弟师妹们别紧张，实在不行就像我一样——放弃治疗。',NULL,'2026-07-09 10:30:49'),(504,20,44,'路明非考完3E出来整个人都是懵的，然后被告知是S级。那个表情我能笑一年。',NULL,'2026-07-09 05:03:49'),(505,20,46,'3E考试最怕的不是考不好，是考到一半言灵失控把考场炸了。别问我怎么知道的。',NULL,'2026-07-08 21:17:49'),(506,20,51,'绘梨衣考3E的时候睡着了……然后醒来就是S级了。绘梨衣也不知道为什么。',NULL,'2026-07-10 18:41:49'),(507,20,52,'哥哥考了S级呢。不愧是我选中的人。',NULL,'2026-07-10 08:11:49'),(508,21,42,'北欧的任务我参加过。那里的环境会对血统产生特殊影响。',NULL,'2026-07-10 10:11:49'),(509,21,49,'执行部已收到简报。相关人员在出发前请到医疗部做血统检测。',NULL,'2026-07-10 14:46:49'),(510,21,47,'我在北欧待过。带上足够的保暖装备，以及——一把好刀。',NULL,'2026-07-10 14:08:49'),(511,21,43,'如果需要加图索家族的支援，说一声。',NULL,'2026-07-11 04:17:49'),(517,31,43,'狮心会招新有实战演练？这倒是不错的方式。学生会的选拔也可以参考。',NULL,'2026-07-09 05:21:49'),(518,31,46,'来狮心会吧！我们有最帅的会长，最好的训练场地，还有一个会偷吃零食的副会长！',NULL,'2026-07-09 15:13:49'),(519,31,45,'体能测试要跑多少米？超过一千米我就不报名了。',NULL,'2026-07-08 17:39:49'),(520,31,42,'不要求长跑成绩。但剑术基础至少要有。',NULL,'2026-07-10 18:59:49'),(521,32,42,'派对很热闹。但请控制音量，宿舍区十点后需要安静。',NULL,'2026-07-11 05:37:49'),(522,32,44,'今年派对我负责布置！保证比去年好看！',NULL,'2026-07-10 20:58:49'),(523,32,45,'去年的派对我喝到了校长的珍藏红酒，今年的酒水预算不会降吧？',NULL,'2026-07-08 15:25:49'),(524,32,47,'执行部将派员维护当晚秩序。请文明饮酒。',NULL,'2026-07-11 01:09:49'),(525,33,47,'你说的那个地方我已经上报执行部了。',NULL,'2026-07-10 00:01:49'),(526,33,50,'图书馆四楼属于管制区域。再次违规将记过处分。',NULL,'2026-07-09 16:00:49'),(527,33,45,'夏弥师妹你又来了哈哈哈哈你是不是想把卡塞尔每一个秘密角落都挖出来？',NULL,'2026-07-10 08:22:49'),(528,33,43,'听起来是个约会的好地方。记下了。',NULL,'2026-07-09 21:47:49'),(529,34,3,'芬格尔师兄推荐的一定要去试试！不过你上次推荐的\"美味营养餐\"可是让我拉了三天肚子。',NULL,'2026-07-10 11:57:49'),(530,34,44,'吃过了。牛肉拉面确实不错，加个煎蛋更香。',NULL,'2026-07-10 13:08:49'),(531,34,51,'绘梨衣也去吃了！不辣的好吃！老板叔叔还多给了绘梨衣几块牛肉！',NULL,'2026-07-08 10:55:49'),(532,34,43,'能让芬格尔连续吃三天的店，确实值得一试。',NULL,'2026-07-10 02:01:49'),(533,34,42,'碳水摄入过多会影响训练状态。适量即可。',NULL,'2026-07-10 11:42:49'),(534,35,47,'归档。下次巡逻我会检查那具标本。',NULL,'2026-07-08 09:22:49'),(535,35,42,'冰窖C区的温度波动需要关注，可能跟封印有关。',NULL,'2026-07-08 16:34:49'),(536,35,45,'零师姐的巡逻报告永远是最标准的。不像某些人的报告，写得像小说。',NULL,'2026-07-11 04:26:49'),(537,35,49,'C区温度异常已记录。技术部下周会进行全面检查。',NULL,'2026-07-11 05:46:49'),(538,35,52,'冰窖里那具标本，左眼确实会发光呢。毕竟——它还没有完全死去。',NULL,'2026-07-09 01:29:49'),(539,37,3,'我也看到了！白色的那只对吧？它特别亲人。',NULL,'2026-07-10 21:07:49'),(540,37,44,'那只猫已经是学院的编外成员了。芬格尔还给它起名叫\"食堂三楼的霸王\"。',NULL,'2026-07-08 21:59:49'),(541,37,47,'校园内的流浪动物由后勤部统一管理。可以投喂，禁止带回宿舍。',NULL,'2026-07-11 08:07:49'),(542,37,45,'我作证，那只猫比我还能吃。昨天它抢了我半根火腿肠。',NULL,'2026-07-10 23:46:49'),(543,37,51,'大家好，这是棉花糖和巧克力！棉花糖是妈妈，巧克力是宝宝！',NULL,'2026-07-08 18:04:49'),(544,38,3,'你小子到底在哪？？？每次发完消息人就消失了。',NULL,'2026-07-09 06:06:49'),(545,38,42,'路明非，你弟弟的事……如果需要帮忙，说一声。',NULL,'2026-07-09 01:30:49'),(546,38,43,'有意思的角色。我查过诺玛的记录，没有这个学生的档案。',NULL,'2026-07-09 16:30:49'),(547,38,47,'执行部没有关于\"路鸣泽\"的任何登记信息。',NULL,'2026-07-09 05:58:49'),(548,38,52,'哥哥别找了。等你想见我的时候，我自然会出现的。',NULL,'2026-07-09 11:11:49'),(549,39,3,'诺诺师姐你这是在点名批评我吧？？我好歹也是个S级，给点面子啊！',NULL,'2026-07-08 10:00:49'),(550,39,45,'总结得太到位了。我建议把这个帖子置顶，让每一个新生都看看。',NULL,'2026-07-10 19:24:49'),(551,39,42,'观察细致。不过S级的潜力往往在关键时刻才会显现。',NULL,'2026-07-08 12:53:49'),(552,39,43,'这个描述……我怎么觉得在说一年前的自己。',NULL,'2026-07-08 22:43:49'),(553,39,46,'哈哈哈哈诺诺师姐你这个帖子我要收藏！路明非你看看你多出名！',NULL,'2026-07-10 04:18:49'),(554,62,43,'楚子航难得说这么多话。不过——我同意。',NULL,'2026-07-10 10:46:49'),(555,62,46,'会长说得真好！狮心会训练的时候他也是这么教我们的。',NULL,'2026-07-08 12:22:49'),(556,62,45,'说得我都想去练剑了。不过还是先吃完这碗拉面再说。',NULL,'2026-07-08 17:48:49'),(557,62,47,'村雨的持有者，说出这番话很有分量。',NULL,'2026-07-10 08:21:49'),(558,62,49,'执行部的理念也是保护。只是我们保护的方式——不太温柔。',NULL,'2026-07-08 11:46:49'),(559,63,46,'会长！我真的是有正事！我去……买冰淇淋了。',NULL,'2026-07-09 16:20:49'),(560,63,44,'夏弥你是真的勇。擅自离校还敢发帖跟会长顶嘴。',NULL,'2026-07-09 00:05:49'),(561,63,45,'师妹别怕！师兄我被记过27次了，现在还活得好好的！',NULL,'2026-07-09 04:06:49'),(562,63,50,'夏弥同学，明天下午三点，风纪委员会办公室。',NULL,'2026-07-10 19:45:49'),(563,63,43,'楚子航的处罚方式很有意思。\"罚扫训练场\"——听起来像恩赐而不是惩罚。',NULL,'2026-07-08 13:04:49'),(564,84,42,'王不是自己封的。是别人愿意跟随你，你才是王。',NULL,'2026-07-10 03:37:49'),(565,84,44,'恺撒难得正经一回。不过说得对，我支持。',NULL,'2026-07-08 18:01:49'),(566,84,45,'主席你这话要是让你家族的人听到，他们可能会震惊。',NULL,'2026-07-08 16:24:49'),(567,84,47,'有道理。执行部的原则也是——走在最前面。',NULL,'2026-07-09 11:41:49'),(568,84,52,'真正的王愿意为身后的人挡住第一刀……这话说得真好。但哥哥，你看到了吗？',NULL,'2026-07-08 13:02:49'),(569,83,42,'领袖不是位置，是担当。',NULL,'2026-07-08 15:20:49'),(570,83,51,'听不太懂……但是感觉好厉害！',NULL,'2026-07-10 11:00:49'),(571,83,47,'领袖的定义有很多种。但恺撒说的这种，值得尊重。',NULL,'2026-07-11 04:50:49'),(572,68,45,'主席你这是针对我！食堂靠窗的位置我睡了两年了！',NULL,'2026-07-10 19:37:49'),(573,68,44,'芬格尔师兄，规定就是规定。你要睡觉回宿舍睡。',NULL,'2026-07-09 16:05:49'),(574,68,46,'哈哈哈哈终于有人管管芬格尔师兄的占座行为了。',NULL,'2026-07-10 16:58:49'),(575,68,43,'规定就是规定。如有异议，请书面提交申诉。',NULL,'2026-07-10 09:30:49'),(576,70,46,'我去我去！好久没出学院了！',NULL,'2026-07-09 16:14:49'),(577,70,51,'绘梨衣也想去！绘梨衣想买新的发卡！',NULL,'2026-07-08 22:03:49'),(578,70,45,'男生可以帮忙拎包吗？我可以！',NULL,'2026-07-10 23:13:49'),(579,70,44,'@fingel_von 你上次说帮忙拎包，结果拎了两袋零食回来。拒绝。',NULL,'2026-07-11 06:07:49'),(580,71,3,'芬格尔师兄的测评——可信度极高。毕竟他吃了七年。',NULL,'2026-07-10 16:19:49'),(581,71,44,'食堂三楼的拉面窗口真的是神级推荐。',NULL,'2026-07-08 08:19:49'),(582,71,43,'食堂测评这个系列不错。下一期写学院咖啡厅吧。',NULL,'2026-07-09 16:41:49'),(583,71,47,'数据详实。建议归档为学院生活指南。',NULL,'2026-07-08 15:18:49'),(584,71,51,'绘梨衣也觉得食堂三楼的拉面最好吃！',NULL,'2026-07-10 22:32:49'),(585,72,3,'师兄你这话说出来，校长办公室的血压又要升高了。',NULL,'2026-07-11 06:11:49'),(586,72,50,'芬格尔同学，你的毕业论文已经延期三年了。',NULL,'2026-07-08 15:29:49'),(587,72,43,'我让人事部把你的毕业年限录入系统了。如果今年再不交，系统会自动报警。',NULL,'2026-07-10 16:26:49'),(588,72,45,'主席！你这是赶尽杀绝！',NULL,'2026-07-08 15:30:49'),(589,72,44,'芬格尔师兄，是时候面对现实了。',NULL,'2026-07-11 06:14:49'),(590,73,42,'……那个房间是我私人用的。你怎么找到的。',NULL,'2026-07-10 03:28:49'),(591,73,46,'会长！我不是故意的！就是……不小心推开了那扇门！',NULL,'2026-07-09 17:45:49'),(592,73,45,'楚师兄看漫画？！这是什么惊天大新闻！',NULL,'2026-07-09 20:13:49'),(593,73,44,'哈哈哈哈楚师兄的秘密基地被曝光了！我要去看！',NULL,'2026-07-09 17:59:49'),(594,73,43,'楚会长，没想到你还有这一面。失敬失敬。',NULL,'2026-07-11 03:17:49'),(595,74,42,'实战技巧分享值得肯定。但第四条攻击方式建议删掉。',NULL,'2026-07-09 14:00:49'),(596,74,45,'学会了！下次跟人打架我就用这招！',NULL,'2026-07-10 18:57:49'),(597,74,47,'风王之瞳的侦查能力确实优秀。执行部的战术手册可以参考。',NULL,'2026-07-10 00:59:49'),(598,74,50,'夏弥同学，你还没有吸取上次的教训吗。',NULL,'2026-07-11 02:24:49'),(599,75,42,'C区存放的东西确实不适合大多数人看到。',NULL,'2026-07-08 14:14:49'),(600,75,45,'我去过一次……然后做了一周的噩梦。',NULL,'2026-07-10 03:54:49'),(601,75,43,'越是不让进的地方，越有人想进。这是人性。',NULL,'2026-07-09 20:19:49'),(602,75,47,'所以我的工作就是守住这些\"不让进\"的地方。',NULL,'2026-07-10 11:28:49'),(603,77,3,'我举报！芬格尔师兄那天确实在女生宿舍楼下！',NULL,'2026-07-11 05:21:49'),(604,77,45,'冤枉啊！我只是路过去食堂！再说小鱼干是咸的我又不是猫！',NULL,'2026-07-08 16:46:49'),(605,77,44,'可是芬格尔师兄，你当时嘴里确实在嚼东西。我有照片为证。',NULL,'2026-07-11 00:53:49'),(606,77,47,'绘梨衣，下次小鱼干放我房间。我帮你看着。',NULL,'2026-07-09 21:13:49'),(607,77,51,'谢谢零姐姐！绘梨衣下次多做一份给零姐姐！',NULL,'2026-07-11 00:10:49'),(608,78,3,'绘梨衣做的巧克力超好吃！！！我给满分！',NULL,'2026-07-10 09:52:49'),(609,78,44,'绘梨衣真棒！下次师姐教你做草莓巧克力！',NULL,'2026-07-09 12:13:49'),(610,78,47,'进步很大。下次注意隔水加热的温度。',NULL,'2026-07-09 10:50:49'),(611,78,45,'我也想要！为什么我没有！我也对绘梨衣很好的！',NULL,'2026-07-09 06:17:49'),(612,78,51,'好呀好呀！绘梨衣做抹茶味的请大家吃！',NULL,'2026-07-08 22:21:49'),(613,79,43,'帕西的保养手艺一直是最好的。狄克推多跟了我这么多年，依然如新。',NULL,'2026-07-10 07:59:49'),(614,79,42,'村雨的保养方式不太一样。有机会可以交流。',NULL,'2026-07-09 19:04:49'),(615,79,45,'我的刀……好像放在某个角落生锈了。',NULL,'2026-07-11 08:02:49'),(616,79,47,'定期保养武器是好习惯。冰窖里的标本不需要保养，但也需要定期检查。',NULL,'2026-07-10 01:35:49'),(617,82,43,'雨中训练——加图索家的传统。楚会长，这方面我们倒是想到一块去了。',NULL,'2026-07-10 15:42:49'),(618,82,46,'会长又在号召大家训练了。你们别去！听我的！',NULL,'2026-07-10 01:22:49'),(619,82,45,'雨天训练？不了谢谢。我选择在宿舍的被窝里远程支持你们。',NULL,'2026-07-09 00:16:49'),(620,82,42,'明天有雨。训练场六点开门。',NULL,'2026-07-10 15:30:49'),(621,85,42,'同意。下次联合训练我不会留手的。',NULL,'2026-07-09 15:18:49'),(622,85,46,'哇！会长和学生会主席要联手训练了！我要围观！',NULL,'2026-07-10 19:20:49'),(623,85,44,'你们两个终于想通了。我一直觉得你们较劲挺浪费时间的。',NULL,'2026-07-09 04:30:49'),(624,85,45,'两大高手联手训练——建议卖门票，收入归学生会经费。',NULL,'2026-07-11 01:56:49'),(625,85,47,'执行部会派观察员记录训练数据。',NULL,'2026-07-08 19:14:49'),(626,87,3,'绘梨衣你怎么把这事也发上来了……怪不好意思的。',NULL,'2026-07-11 02:40:49'),(627,87,44,'路明非你明明就是个很温柔的人，干嘛总装作一副吊儿郎当的样子。',NULL,'2026-07-08 10:36:49'),(628,87,47,'路明非，继续保持。',NULL,'2026-07-08 17:34:49'),(629,87,45,'没想到师弟还是个暖男！师兄我感动了！今晚请我吃饭吧！',NULL,'2026-07-08 15:35:49'),(630,87,51,'路明非哥哥就是很温柔！绘梨衣说的都是真的！',NULL,'2026-07-10 01:33:49'),(631,88,3,'你能不能别每次都发这种让人心里发毛的话……',NULL,'2026-07-10 19:35:49'),(632,88,42,'路鸣泽，如果你真的关心你哥，不如当面跟他谈谈。',NULL,'2026-07-11 01:49:49'),(633,88,43,'这个论坛上最神秘的用户。你的ID我查不到任何信息。',NULL,'2026-07-10 11:24:49'),(634,88,47,'查无此人。但消息确实发出来了。',NULL,'2026-07-11 06:17:49'),(635,88,52,'哥哥，当面谈就没意思了。我喜欢在暗处看着你。',NULL,'2026-07-08 12:19:49'),(636,89,43,'帕西，你总是这样——默默付出，从不邀功。',NULL,'2026-07-09 08:47:49'),(637,89,42,'忠诚是一种选择。帕西选择了值得效忠的人。',NULL,'2026-07-08 12:33:49'),(638,89,47,'记录详实。值得执行部学习。',NULL,'2026-07-08 21:46:49'),(639,89,53,'职责所在。',NULL,'2026-07-09 10:17:49'),(640,90,3,'零师姐你看到了！那个……我就是觉得他一个人在里面挺可怜的。',NULL,'2026-07-08 19:42:49'),(641,90,47,'我知道。所以我把小鱼干放回去了。',NULL,'2026-07-09 22:29:49'),(642,90,45,'路明非给冰窖里的东西送吃的？！师弟你的胆子是越来越大了！',NULL,'2026-07-09 18:55:49'),(643,90,42,'康斯坦丁……你见过他了？',NULL,'2026-07-08 13:47:49'),(644,90,3,'没见到本人……不对，本龙。我就是把小鱼干放在门口了。',NULL,'2026-07-09 06:07:49'),(645,90,52,'哥哥真是个善良的人呢。不过——小心别喂太多，龙王也是会挑食的。',NULL,'2026-07-10 22:45:49'),(646,80,1,'你挺仁义',NULL,'2026-07-11 09:42:07'),(648,95,77,'我所在区域同样遭受极大温度困扰',NULL,'2026-07-11 15:03:48'),(649,93,80,'有龙王诞生的迹象吗',NULL,'2026-07-11 15:25:27'),(652,95,80,'我执行任务的辖区也被影响，疑似青铜与火之王复苏',NULL,'2026-07-11 15:27:17'),(653,82,80,'雨中训练吗？有点意思',NULL,'2026-07-11 15:29:15'),(655,95,1,'祝好运',652,'2026-07-11 19:36:27'),(656,87,1,'你小子最精了',626,'2026-07-11 19:39:31'),(661,93,3,'不太确定，道听途说的😁',649,'2026-07-11 23:29:59'),(662,92,3,'注册审核在左上角导航栏！',NULL,'2026-07-12 00:32:31');
