INSERT INTO `news` VALUES (2,'秘党最新研究：龙族血统与元素共鸣的深层关联','秘党研究院今日发布了一份关于龙族血统与元素共鸣关联性的最新研究报告。报告指出，高等级血统（A级及以上）的混血种在与特定元素接触时，表现出显著高于普通混血种的共鸣频率。\n\n研究团队通过对57名志愿者的血统样本分析发现，S级血统拥有者对火元素的共鸣强度是D级血统的约12倍。这一发现可能为开发新型言灵之术提供理论基础。\n\n报告全文已在秘党内刊发布，感兴趣的学员可前往图书馆查阅。',NULL,'秘党发布血统研究新成果，S级血统火元素共鸣强度为D级的12倍。','秘党研究院',0,'2026-07-10 11:57:07','2026-07-10 11:57:07'),(3,'狮心会与学生会联合声明：年度学院竞赛即将开幕','卡塞尔学院两大核心社团——狮心会与学生会今日联合宣布，2026年度学院竞赛将于两周后正式开幕。本次竞赛将包含言灵对战、学术辩论、野外生存等多个项目。\n\n狮心会会长与学生会主席共同表示，本届竞赛旨在促进各社团交流，发掘优秀人才，同时为即将到来的毕业季预热。\n\n报名截止日期为本月25日，参赛者可通过各自社团提交报名申请。优胜者将获得由学院颁发的荣誉勋章及特殊权限。',NULL,'年度学院竞赛两周后开幕，包含言灵对战、学术辩论等项目。','狮心会·学生会',1,'2026-07-10 11:57:07','2026-07-10 11:57:07'),(4,'执行部报告：北欧地区发现疑似龙类遗迹','卡塞尔学院执行部今日提交了一份关于北欧地区最新发现的勘察报告。报告显示，在挪威北部山区发现了一处疑似古龙类活动的遗迹，现场检测到微弱的元素波动。\n\n执行部已派遣先遣队前往现场进行进一步勘察，预计两周内返回初步评估结果。校方提醒各位学员，目前该区域已被划为临时禁区，未经执行部许可不得擅自前往。\n\n这处遗迹的年代初步判定为公元9世纪左右，与北欧传说中的龙类活动高峰期吻合。如有进一步消息，执行部将及时通报。',NULL,'挪威北部发现疑似古龙遗迹，元素波动已被检测到，执行部已派遣先遣队。','执行部',0,'2026-07-10 11:57:07','2026-07-10 11:57:07'),(5,'诺玛系统全面升级：新增邮件通讯与联系人功能','尊敬的各位学员，卡塞尔学院中央控制系统「诺玛」已完成全面升级。本次升级新增以下功能：\n\n📰 新闻板块：实时获取学院官方发布的新闻与公告，了解龙族世界最新动态。\n✉️ 邮件系统：诺玛将统一分发重要通知与个人消息至您的专属邮箱，确保不错过任何关键信息。\n👥 联系人：支持通过学员ID搜索并添加好友，与同学保持联系，查看好友在线状态。\n\n请登录您的账号体验全新功能。如有任何问题或建议，请联系系统管理员。\n\n——诺玛',NULL,'诺玛系统全面升级！新增新闻、邮件、联系人三大板块，提升社区体验。','诺玛',1,'2026-07-10 11:57:07','2026-07-10 11:57:07'),(6,'Edited News','Edited content',NULL,'Edited summary','诺玛',0,'2026-07-10 12:37:41','2026-07-10 12:37:41'),(7,'楚子航晋升执行部分队长','经执行部考核委员会评定，楚子航同学在言灵·君焰的应用与实战演练中表现卓越，正式晋升为执行部第三分队队长。楚子航是目前学院最年轻的分队长之一。',NULL,'楚子航正式晋升执行部分队长，成为学院最年轻的分队长之一。','执行部',0,'2026-07-06 14:53:03','2026-07-10 14:53:02'),(8,'昂热校长将出席国际秘党峰会','卡塞尔学院校长希尔伯特·让·昂热将于下周前往瑞士日内瓦，出席由国际秘党元老会召集的紧急峰会。据信，峰会主题与近期北欧发现的多处龙类遗迹有关。',NULL,'昂热校长下周赴日内瓦出席秘党紧急峰会，议题涉及北欧龙类遗迹。','校长办公室',1,'2026-07-04 14:53:03','2026-07-10 14:53:02'),(9,'龙族文字破译取得重大突破','卡塞尔学院语言学研究组宣布，通过对挪威遗迹出土的符文石刻进行分析，已成功破译了海洋与水之王时代的部分龙族文字。这项成果将极大推动龙族历史研究的进展。',NULL,'学院语言组破译海洋与水之王时代龙族文字，推动历史研究。','学术委员会',0,'2026-07-02 14:53:03','2026-07-10 14:53:02'),(10,'言灵·时间零的修炼风险警告','近期有学员在未授权情况下私自尝试修炼高阶言灵·时间零，执行部已介入调查。校方重申：时间零属于A级及以上高危言灵，需在导师全程监督下进行。私自修炼可能导致不可逆的时间流反噬。',NULL,'警告：言灵·时间零私自修炼存在高风险，校方严禁未授权修炼。','执行部',0,'2026-07-08 14:53:03','2026-07-10 14:53:02'),(11,'年度学院竞赛赛程公布','2026年度学院竞赛组委会今日公布完整赛程。本次竞赛新增\"遗迹探索\"与\"古文字破译\"两个项目，共设六大竞赛单元。决赛将在卡塞尔学院主竞技场举行，届时全校直播。',NULL,'年度竞赛赛程公布，新增遗迹探索与古文字破译两大项目。','竞赛组委会',1,'2026-07-07 14:53:03','2026-07-10 14:53:02'),(12,'秘银价格持续上涨引发炼金材料紧缺','据学院炼金术系报告，由于全球秘银产量下降，秘银市场价格在过去三个月上涨了47%。多门炼金实验课面临材料短缺。校方已启动战略储备方案，并与秘党矿业部门协商增加供应。',NULL,'秘银价格上涨47%，炼金课材料短缺，校方启动储备方案。','炼金术系',0,'2026-06-30 14:53:03','2026-07-10 14:53:02'),(13,'路明非被提名年度杰出学员','学生会今日宣布，路明非同学因在自由一日中的出色表现以及对社团活动的积极参与，被提名为2026年度卡塞尔学院杰出学员候选人。其他候选人还包括楚子航和恺撒·加图索。最终结果将在年度竞赛闭幕式上公布。',NULL,'路明非提名年度杰出学员，与楚子航、恺撒共同角逐。','学生会',0,'2026-07-05 14:53:03','2026-07-10 14:53:02'),(14,'施耐德教授发布龙族生态研究报告','执行部部长施耐德教授在最新一期的《秘党学术月刊》上发表了关于龙族生态系统的长篇研究报告。报告基于三十年追踪数据，揭示了龙族在不同环境的适应机制与进化路径。',NULL,'施耐德教授发布龙族生态研究，揭示龙族适应机制与进化路径。','执行部',0,'2026-06-28 14:53:03','2026-07-10 14:53:02'),(16,'测试','这是一个测试','','测试','诺玛',0,'2026-07-10 18:25:58','2026-07-10 18:25:58');
/*!40000 ALTER TABLE `news` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `post`
--

DROP TABLE IF EXISTS `post`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `post` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '帖子ID',
  `title` varchar(200) NOT NULL COMMENT '标题',
  `content` text NOT NULL COMMENT '正文内容',
  `category` tinyint NOT NULL DEFAULT '1' COMMENT '分类：1-闲聊 2-史料 3-委托 4-交换',
  `user_id` bigint NOT NULL COMMENT '发布者用户ID',
  `view_count` int NOT NULL DEFAULT '0' COMMENT '浏览量',
  `comment_count` int NOT NULL DEFAULT '0' COMMENT '评论数',
  `is_top` tinyint NOT NULL DEFAULT '0' COMMENT '是否置顶：0-否 1-是',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_category` (`category`),
  KEY `idx_is_top` (`is_top`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=110 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='帖子表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `post`
--

LOCK TABLES `post` WRITE;
/*!40000 ALTER TABLE `post` DISABLE KEYS */;
INSERT INTO `post` VALUES (11,'【委托】寻找失落的高阶炼金术笔记','据执行部档案记载，二战期间有一位S级前辈在柏林执行任务时遗落了一本炼金术研究笔记。该笔记记载了关于青铜与火之王的精炼配方，对目前的龙类研究极具价值。\n\n现委托各位学员，如有任何关于这本笔记下落的线索，请通过邮件与我联系。报酬面议。\n\n——学生会学术部',3,1,925,4,0,'2026-06-28 14:46:44','2026-07-11 09:13:48'),(12,'今天在图书馆看到了楚子航','他坐在靠窗的位置看书，旁边没有人敢靠近……那种气场真的无法形容。\n\n我鼓起勇气想过去问他关于言灵·君焰的修炼方法，但走到一半腿就不听使唤了。\n\n有人跟他说过话吗？他是不是真的那么可怕？',1,3,2340,5,0,'2026-07-03 14:46:44','2026-07-11 09:13:48'),(13,'狮心会招收新成员公告','狮心会2026年度春季招新正式开启。\n\n入选标准：\n1. 血统等级B级及以上\n2. 通过体能测试与言灵实战考核\n3. 认同狮心会\"守护人类、猎杀龙族\"的宗旨\n\n报名请到狮心会总部领取申请表，截止日期本月30日。\n\n——狮心会 会长',1,1,1354,4,0,'2026-07-07 14:46:44','2026-07-11 09:13:48'),(15,'恺撒又帮路明非订座了','今天在Rotfront餐厅看到路明非一个人坐在包间里，后来才知道是恺撒提前帮他订的。\n\n据说因为上次自由一日的时候恺撒输给了路明非，所以对他格外照顾？\n\n这两人的关系到底算敌人还是朋友啊……',1,3,5946,5,0,'2026-07-08 14:46:44','2026-07-12 09:52:37'),(16,'自由一日复盘帖：学生会失利分析','自由一日已经过去两周了，作为一个旁观者复盘一下学生会的战术。\n\n1. 恺撒使用了言灵·镰鼬，理论上应该占据信息优势，但路明非的战术实在太诡异了\n2. 学生会过于依赖恺撒的个人能力，团队配合出现断层\n3. 路明非利用了卡塞尔学院的地形优势和出其不意的战术思路\n\n欢迎理性讨论。',1,1,2918,5,0,'2026-07-02 14:46:44','2026-07-11 09:42:38'),(17,'【史料】关于白王的历史考证','最近在古籍中翻到一段关于白王的有趣记载。\n\n根据公元9世纪的北欧手稿，白王曾经与青铜与火之王爆发过一次规模空前的战争，战场位于现在的格陵兰岛附近。当时海洋沸腾了三天三夜，天空被染成红色。\n\n有没有人对这段历史感兴趣的一起研究？\n\n——历史研究组',2,1,1668,4,0,'2026-06-26 14:46:44','2026-07-12 07:55:51'),(20,'新生3E考试经验分享','刚通过3E考试，血统评定B级，给大家分享一下经验。\n\n1. 历史类题目占比最高，建议考前多看《龙族通史》前五章\n2. 困境选择题的答案不是选\"最英勇\"的，而是选\"最合理\"的\n3. 血统测试不要紧张，紧张反而会影响结果\n\n各位新生加油，3E考试没有想象中那么可怕。',1,3,6959,7,0,'2026-07-06 14:46:44','2026-07-11 22:46:42'),(21,'执行部近期在北欧有新发现','听执行部的前辈说，挪威那边的勘察队已经发回了初步报告。遗址里发现了一些符文石刻，初步判断属于海洋与水之王时代的遗物。\n\n如果确认的话，这将是近二十年来最重要的龙族遗迹发现之一。\n\n不过目前还是机密，详细内容可能要等执行部正式通报。',2,1,2094,4,0,'2026-07-04 14:46:44','2026-07-11 09:13:48'),(31,'关于狮心会招新的几点说明','本学期狮心会招新工作即将开始。以下几点请有意加入的同学注意：\n\n1. 招新面试定于本周六下午2点，在3号教学楼201教室\n2. 请携带血统测评报告复印件\n3. 面试将包含基础体能测试\n4. 无需提前准备，临场发挥也是考察的一部分\n\n有意者请在本帖下回复报名。\n——狮心会会长 楚子航',1,42,112,4,0,'2026-07-09 19:21:15','2026-07-11 09:13:48'),(32,'学生会公告：迎新派对','各位新同学，我是学生会主席恺撒·加图索。\n\n按照惯例，学生会将在本周五晚举办本学年最盛大的迎新派对。地点在学院宴会厅，酒水畅饮，音乐不停。\n\n特别注意：着装要求——正装。不允许穿拖鞋和睡衣入场，芬格尔，说的就是你。\n\n报名方式：在本帖下回复即可。加图索家的派对，不来是你的损失。',1,43,128,4,0,'2026-07-10 01:21:15','2026-07-11 09:13:48'),(33,'图书馆四楼有个秘密角落','嘘——告诉你们一个秘密。\n\n图书馆四楼最里面那排书架后面，有一扇不起眼的门。推开门是一个小阳台，能看到整个卡塞尔学院的日落。风从山那边吹过来的时候，能听到钟楼的钟声。\n\n我是在逃课的时候发现的，但别告诉曼施坦因教授。\n\n那里是我在卡塞尔最喜欢的地方，现在分享给你们。不过去的人太多了我就不去了，毕竟——我是师姐了嘛，要成熟一点。',1,46,191,4,0,'2026-07-10 07:21:15','2026-07-11 12:31:26'),(34,'【情报】关于食堂三楼新开的窗口','独家情报！食堂三楼新开了一个窗口，老板是中国人，卖的是正宗兰州拉面。\n\n我芬格尔以F级的名誉担保，这绝对是我在卡塞尔三年来吃过最好吃的东西。一碗牛肉拉面，加辣加香菜，只要5卡塞尔币。\n\n唯一的缺点是排队的人太多了，建议下午三点去，避开高峰期。\n\n——你们亲爱的F级师兄 芬格尔',1,45,53,5,0,'2026-07-10 11:21:15','2026-07-11 09:13:48'),(35,'任务报告：冰窖日常巡逻记录','执行部冰窖巡逻任务记录。\n\n日期：本周三\n巡逻人员：零\n\nB区第七层封印正常。C区第三号储藏柜温度偏高0.3度，已做记录并上报。东侧走廊监控摄像头的红外感应器有间歇性故障，已通知技术部维修。\n\n无异常情况。\n\n另：冰窖里的那具龙类标本，左眼在夜里好像会发光。建议技术部检查一下。\n——执行部 零',1,47,103,5,0,'2026-07-10 13:21:15','2026-07-11 22:17:06'),(37,'今天在校园里看到一只小猫','今天在校园里看到一只白色的小猫，它蹲在喷泉旁边舔爪子。绘梨衣蹲下来看着它，它也不怕绘梨衣，还走过来蹭了蹭绘梨衣的脚。\n\n绘梨衣很开心。但是零姐姐说不能带回宿舍。\n\n小猫你明天还会在这里吗？绘梨衣带了小鱼干来。\n\n(附：谢谢路明非哥哥给绘梨衣买的小鱼干)',1,51,144,5,0,'2026-07-10 23:21:15','2026-07-11 19:36:58'),(38,'给哥哥的一封信','亲爱的哥哥：\n\n你最近过得还好吗？卡塞尔的生活还习惯吗？\n\n我知道你看到这封信一定会很惊讶——你的弟弟怎么会在这个论坛上。但你看，互联网就是这么神奇的东西。\n\n顺便说一句，楚师兄的那把村雨，刀鞘里藏着的东西你注意到了吗？诺诺姐的红色跑车，油箱盖下面有一把备用钥匙。\n\n我只是随便说说，你别往心里去。\n\n什么时候想我了，就抬头看看月亮吧。\n——你的弟弟 路鸣泽',1,52,20,5,0,'2026-07-11 01:21:15','2026-07-11 23:13:15'),(39,'论如何正确识别一个S级菜鸟','分享一个快速识别S级新生的方法：\n\n1. 走路低着头，看起来特别怂\n2. 说话结结巴巴，一副\"我什么都不会\"的样子\n3. 但一到考试或者实战，画风突变\n4. 通常身边会有一个看起来跟他完全不是一个画风的朋友\n\n参考案例：路明非。\n\n别问我怎么知道的。作为师姐，我看人一向很准。\n\n顺便提醒某些人，S级不代表可以逃掉狮心会的训练课哟 @路明非',1,44,197,5,0,'2026-07-11 03:21:15','2026-07-12 00:08:38'),(62,'剑术的本质不是杀人，是保护','最近在指导新学员的时候，有人问我：\"楚师兄，剑术练到最后是什么？\"\n\n我想了很久。小时候练剑，是为了变强。进了狮心会，是为了守护。执行部出任务，是为了不让更多人死去。\n\n剑术的本质不是杀戮。村雨不是为斩人而铸的——它是为斩断不该存在的东西。\n\n如果你也正在练剑，记住这一点：握刀的手，也可以握住别人的手。',2,42,745,5,0,'2026-07-08 17:51:15','2026-07-11 13:06:20'),(63,'关于夏弥擅自离校的报告','狮心会副会长夏弥，于本周三未经报备擅自离校，次日凌晨从图书馆四楼阳台翻窗返回宿舍。\n\n已对其进行口头警告。但鉴于夏弥同学认错态度良好，且系初犯，建议从轻处理。\n\n附：下次再犯，罚扫狮心会训练场一个月。\n——楚子航',1,42,373,5,0,'2026-07-09 03:40:15','2026-07-11 17:37:42'),(67,'关于「领袖」的定义','有人问我，什么样的人才能做领袖。\n\n答案很简单：当所有人都在后退的时候，你站在那里。不是因为你勇敢，而是因为你知道——身后没有人了。\n\n加图索家的家训从来不是\"统治\"，而是\"守护\"。守护你的家族，守护你的同伴，守护你认为对的事。\n\n所以路明非，下次任务别躲在我后面了。你也是S级。到我身边来。',4,43,305,0,0,'2026-07-09 10:49:15','2026-07-11 15:29:49'),(68,'学生会内部通告——关于食堂抢占座位的若干规定','近日收到大量新生投诉，称食堂三楼靠窗位置长期被某F级师兄霸占用于午睡。\n\n经学生会研究决定：\n1. 食堂座位实行\"先到先得，人走座空\"原则\n2. 禁止用书包、外套等物品长期占座\n3. 特别针对芬格尔·冯·弗林斯同学——禁止在食堂座位上睡觉超过30分钟\n\n以上规定自发布之日起执行。\n——学生会主席 恺撒·加图索',2,43,788,4,0,'2026-07-08 15:31:15','2026-07-11 09:13:48'),(70,'周末一起去市区逛街吧','这周末天气不错，打算去市区转转。\n\n目标：新开的商场、那家据说很好吃的甜品店、还有——给绘梨衣买几个新发卡。\n\n有意向的姐妹评论区举手。\n\n（男生勿扰，除非你愿意帮忙拎包。）',3,44,290,4,0,'2026-07-10 21:34:15','2026-07-11 19:36:50'),(71,'【重磅】卡塞尔餐厅测评——第一弹','各位学弟学妹们，师兄我花了七年时间，吃遍了卡塞尔每一个可以吃东西的地方。今天开始做一个系列测评。\n\n第一期：食堂一楼\n推荐指数：★★☆☆☆\n理由：中规中矩，土豆炖牛肉里的牛肉需要拿显微镜找。\n\n第二期：食堂二楼（自选窗口）\n推荐指数：★★★☆☆\n理由：选择多，味道尚可。推荐糖醋里脊，是大师傅的拿手菜。\n\n第三期：食堂三楼（兰州拉面窗口）\n推荐指数：★★★★★\n理由：我芬格尔愿意用F级的尊严发誓，这是我吃过最好吃的拉面。\n\n下期预告：学院咖啡厅的隐藏菜单。',1,45,349,5,0,'2026-07-09 11:47:15','2026-07-11 09:13:48'),(72,'关于我毕业论文的进度说明','收到很多同学和老师的关心，在此统一回复：\n\n我的毕业论文题目是《论卡塞尔学院食堂菜谱变迁与混血种体能需求的相关性研究》。\n\n目前已完成的章节：第一章（引言）写了三段。\n\n预计完成时间：等我再吃一年食堂收集够数据再说。\n\n谢谢大家的关心。另：昂热校长的红酒真好喝。',1,45,394,5,0,'2026-07-09 13:27:15','2026-07-11 15:07:23'),(73,'狮心会的秘密基地被我发现了','狮心会训练场后面有一个小仓库，里面堆满了旧训练器材。\n\n但是——推开最里面那个柜子，后面有一扇门。\n\n门后面是一个大概十平米的小房间，有一张沙发、一盏落地灯、还有一个书架，上面全是漫画书。\n\n沙发靠背上用马克笔写着：\"楚子航的私人领地，闯入者死。\"\n\n狮心会会长大人，没想到你是这样的楚师兄哈哈哈哈哈哈！\n\n放心，我不会告诉别人的。除非你请我吃冰淇淋。',3,46,724,5,0,'2026-07-10 06:21:15','2026-07-11 09:13:48'),(74,'风王之瞳的正确用法——实战篇','上次发了风王之瞳的偷听教程之后，曼施坦因教授又给我记了一笔。\n\n好吧，今天说点正经的。\n\n风王之瞳在实战中的用法：\n1. 侦查：风是你的眼睛，30米范围内任何动静都逃不过\n2. 干扰：定向风力可以扰乱对方的攻击轨迹\n3. 防御：压缩空气形成屏障，可以挡子弹（限3发以内）\n4. 攻击：这个就不说了，怕被教授看见\n\n师姐只能帮你们到这里了。',4,46,387,4,0,'2026-07-09 19:44:15','2026-07-11 15:29:22'),(75,'冰窖C区——为什么总有人想闯进去','本月第三次抓到有人在冰窖C区附近鬼鬼祟祟。\n\nC区存放的是……算了，说了你们也听不懂。\n\n总之：\n1. 冰窖不是观光景点\n2. C区不是约会场所\n3. 再抓到人直接扭送执行部\n\n——零 留',1,47,209,4,0,'2026-07-10 20:48:15','2026-07-11 14:59:43'),(77,'绘梨衣的小鱼干被偷了','呜……绘梨衣放在窗台上晒的小鱼干，今天早上发现少了一半。\n\n绘梨衣问了零姐姐，零姐姐说不是她拿的。\n问了诺诺姐姐，诺诺姐姐说可能是小猫拿的。\n绘梨衣觉得小猫没有那么高，窗台很高很高的。\n\n后来路明非哥哥说——他昨天看到芬格尔师兄从女生宿舍楼下经过，嘴里还在嚼什么东西。\n\n芬格尔师兄！！！那是绘梨衣给喷泉小猫准备的！！！',1,51,832,5,0,'2026-07-08 23:11:15','2026-07-11 09:13:48'),(78,'今天学会了做巧克力','今天零姐姐教绘梨衣做手工巧克力！\n\n第一步：把巧克力切碎。绘梨衣切得很好！只有两块掉地上了。\n第二步：隔水加热搅拌。零姐姐说不能太热，绘梨衣很小心。\n第三步：倒进模具里。绘梨衣做了小熊形状的！\n第四步：放进冰箱等它变硬。\n\n做好的巧克力，绘梨衣送了一块给路明非哥哥，一块给零姐姐，一块给诺诺姐姐。\n还有一块——绘梨衣自己吃了。\n好吃！下次绘梨衣要做抹茶味的！',2,51,398,5,0,'2026-07-09 07:05:15','2026-07-11 16:53:44'),(79,'猎刀保养心得','狄克推多和奥古斯都是孪生刀。\n\n恺撒少爷的狄克推多我每个月都会保养一次。\n\n步骤：清灰→上油→打磨→抛光。\n\n一把好刀跟一个忠诚的仆人一样，不需要说话，只需要在需要的时候——不出错。',3,53,472,4,0,'2026-07-10 01:47:15','2026-07-11 10:04:45'),(80,'无题','少爷今天在训练中被楚子航的剑气划伤了手臂。\n\n伤口不深，我已经处理好了。\n\n但少爷笑着说：\"帕西，你说我跟楚子航，到底谁更强？\"\n\n我没有回答。\n\n因为我的职责不是评判，而是——确保少爷永远不会输。\n\n即使要我用命去换。',4,53,769,1,0,'2026-07-09 21:45:15','2026-07-11 09:42:07'),(82,'雨天训练的特别意义','雨天训练是我个人的习惯。\n\n不是因为我喜欢淋雨。是因为真正的战斗不会挑天气。\n\n在雨中，视线会模糊，地面会打滑，刀的重量会增加——但你的对手也一样。\n\n所以下次下雨的时候，别躲在宿舍里了。来训练场。\n\n我在这里等你。',4,42,227,5,0,'2026-07-09 23:35:43','2026-07-11 15:29:15'),(83,'合作比竞争更重要','今天是跟狮心会联合训练的日子。\n\n看着楚子航站在我对面，我忽然意识到一件事：\n\n我们在学院里争了这么久——但真正上战场的时候，站在我身边的可能就是他。\n\n所以，楚会长。下次训练，我不会留手。\n希望你也是。',1,43,397,3,0,'2026-07-10 00:35:43','2026-07-11 09:13:48'),(84,'关于「王」的定义','加图索家的男人从小就被教育一件事：你是王。\n\n但我在卡塞尔学到了另一件事：\n\n真正的王，不是站在最高处发号施令的人。\n而是愿意走到最前面，为身后的人挡住第一刀的人。',1,43,389,5,0,'2026-07-11 05:35:43','2026-07-11 22:33:07'),(85,'今天在图书馆看到的一幕','今天在图书馆看到楚子航在指导路明非写作业。\n\n楚师兄讲得很认真，路明非听得很认真——虽然从他的表情来看，大概率没听懂。\n\n然后楚师兄叹了口气，把本子拿过来，直接帮他把题做了。\n\n还写了批注：下次不会的来问我。\n\n……楚师兄你是不是太宠他了？',1,44,601,5,0,'2026-07-10 21:35:43','2026-07-11 19:37:11'),(87,'今天在喷泉边遇到了路明非哥哥','今天绘梨衣在喷泉边喂小猫的时候，路明非哥哥也来了。\n\n他带了一整袋猫粮和一盒牛奶。\n\n绘梨衣问他为什么对小猫这么好。\n\n路明非哥哥说：因为没有人对它们好的时候，至少还有我能对它们好。\n\n绘梨衣觉得，路明非哥哥是一个很温柔的人。',4,51,622,6,0,'2026-07-09 16:35:43','2026-07-11 19:40:28'),(88,'哥哥不在的时候','哥哥最近不在线。\n\n大概是忙着在卡塞尔跟朋友们一起玩吧。\n\n也好。\n\n不过哥哥，你有没有想过——\n你身边的那些朋友，真的是朋友吗？\n\n……我只是随便问问。别往心里去。',3,52,477,5,0,'2026-07-09 15:35:43','2026-07-11 09:13:48'),(89,'日常记录','少爷今天心情不错。\n\n原因是他在训练中赢了一局。\n\n我没告诉他楚子航今天右手有伤。\n\n少爷需要的是自信，不是公平。',1,53,521,4,0,'2026-07-09 09:35:43','2026-07-11 09:21:15'),(90,'冰窖巡查日志——特别篇','今天在冰窖B区巡查时，发现角落里有一袋小鱼干。\n\n上面贴着一张纸条：给康斯坦丁——路明非。\n\n……冰窖里没有人。但他好像还是送了。\n\n我把小鱼干放回了原位。\n\n就当没看见。',3,47,474,6,0,'2026-07-10 15:35:43','2026-07-11 20:26:46'),(92,'新用户注册必看！！！','由于注册需要通过管理员账号审核通过才能正常登陆，但是作者本人懒得帮你们审核，所以在这里把昂热校长管理员账号下放给你们，该管理账号只有审核注册的权限：账号：ange   密码：155262',1,1,65,1,1,'2026-07-11 09:34:51','2026-07-12 07:53:00'),(93,'北市有明显地震？','根据新闻报道，北市地铁站处有明显地震，地震导致多人受伤',1,75,34,2,0,'2026-07-11 09:56:09','2026-07-11 23:29:59'),(95,'热热热热热热','我作为专员来到x市进行调查任务，h市我严重怀疑这里有青铜与火之王',1,3,67,3,0,'2026-07-11 14:04:24','2026-07-11 20:32:35'),(96,'关于网站的建议','大家好，我是作者本人，如果有什么页面设计，或者新的功能的相关建议可以向我发邮件或私信，我会根据可行度进行修改和更新，谢谢大家的支持',1,1,59,0,0,'2026-07-11 15:19:17','2026-07-12 00:20:47');
